_REGISTRY = {}   # custom name -> factory(spec) -> Provider


def register(name, factory):
    """Register a custom provider: ``factory`` takes a ``ModelSpec``, returns a ``Provider``."""
    _REGISTRY[name] = factory


def known_providers():
    return sorted(set(_OPENAI_COMPAT) | {"anthropic", "gemini", "mock"} | set(_REGISTRY))


def get_provider(spec):
    name = spec.provider
    if name in _REGISTRY:
        return _REGISTRY[name](spec)
    if name == "mock":
        return MockProvider(model=spec.model)
    if name in _OPENAI_COMPAT:
        return _make_openai_compat(name, spec)
    if name == "anthropic":
        return AnthropicProvider(model=spec.model, base_url=spec.base_url, key_env=spec.key_env)
    if name == "gemini":
        return GeminiProvider(model=spec.model, base_url=spec.base_url, key_env=spec.key_env)
    raise ValueError(
        f"unknown provider {name!r}. Known: {', '.join(known_providers())}. "
        f"Add one with aieasybatch.register({name!r}, factory)."
    )


def _make_openai_compat(name, spec):
    base_url, key_env, opts = _OPENAI_COMPAT[name]
    routing = spec.extra.get("routing") if opts.get("supports_routing") else None
    return OpenAICompatProvider(
        model=spec.model,
        base_url=spec.base_url or base_url,
        key_env=spec.key_env or key_env,
        reasoning_effort=spec.reasoning_effort,
        routing=routing,
        extra_headers=opts.get("headers"),
        provider_name=name,
    )

# ===== core.py =====
@dataclass
class RunResult:
    path: str | None
    ok: int
    failed: int
    run_id: str
    _records: list | None = None

    def records(self):
        """Yield the run's records as dicts (from memory if ``out=""``, else re-read the file)."""
        if self._records is not None:
            yield from self._records
        elif self.path:
            for line in Path(self.path).read_text(encoding="utf-8").splitlines():
                if line.strip():
                    yield json.loads(line)


def _err_type(exc) -> str:
    transient = getattr(exc, "transient", None)
    if transient is True:
        return "transient"
    return "permanent"


def _completed_ids(path, retry_errors):
    """custom_ids already finished in ``path`` (success, or permanent error if not retrying)."""
    done = set()
    for line in Path(path).read_text(encoding="utf-8").splitlines():
        if not line.strip():
            continue
        try:
            rec = json.loads(line)
        except Exception:
            continue
        cid = rec.get("custom_id")
        if not cid:
            continue
        err = rec.get("error")
        if err is None:
            done.add(cid)
        elif not retry_errors and err.get("type") == "permanent":
            done.add(cid)
    return done


def _open_sink(out, resume):
    """Return (path_or_None, write_fn_or_None, close_fn_or_None, in_memory_bool)."""
    if out == "-":
        return None, (lambda line: sys.stdout.write(line + "\n")), None, False
    if out == "" or out is None:
        return None, None, None, True
    path = str(out)
    fh = open(path, "a" if resume else "w", encoding="utf-8")

    def write(line):
        fh.write(line + "\n")
        fh.flush()

    return path, write, fh.close, False


def run(prompts, models, out="run.jsonl", *,
        repeats=1, temperature=1.0, top_p=1.0, max_tokens=512, seed=0,
        concurrency=16, per_model_concurrency=None,
        resume=False, retry_errors=False,
        system=None, on_record=None, registry=None, prices=None,
        timeout=60.0, max_retries=4):
    """Fan a list of prompts across a roster of models and collect every answer.

    Parameters mirror the CLI. ``prompts`` and ``models`` accept lists, file paths, or
    ``"-"`` (stdin) — see ``load_prompts`` / ``load_roster``. ``out`` is a file path,
    ``"-"`` for stdout, or ``""`` to keep records in memory (``RunResult.records()``).
    Returns a ``RunResult`` (``path, ok, failed, run_id``).
    """
    prompt_list = load_prompts(prompts)
    roster = load_roster(models)
    run_id = uuid.uuid4().hex[:12]

    # One provider per distinct model, built once and reused. A build failure (e.g. a
    # missing API key) skips that whole model with a clear message rather than emitting
    # an error record per cell — it's a config problem, not a per-call one.
    providers, sems = {}, {}
    for spec in roster:
        if spec.label in providers:
            continue
        try:
            providers[spec.label] = (registry.get(spec) if registry is not None
                                     else get_provider(spec))
        except Exception as exc:
            print(f"[skip] {spec.label}: {exc}", file=sys.stderr)
            providers[spec.label] = None
        if per_model_concurrency:
            sems[spec.label] = threading.BoundedSemaphore(per_model_concurrency)

    done = (_completed_ids(out, retry_errors)
            if resume and isinstance(out, str) and out not in ("", "-") and Path(out).exists()
            else set())

    # Build the grid: model × prompt × repeat, skipping cells already done.
    tasks = []
    for spec in roster:
        if providers.get(spec.label) is None:
            continue
        spec_max = spec.max_tokens or max_tokens
        for p in prompt_list:
            for r in range(repeats):
                cid = custom_id(spec.provider, spec.model, p.text, system, r)
                if cid in done:
                    continue
                sampling = Sampling(temperature=temperature, top_p=top_p, max_tokens=spec_max,
                                    seed=(None if seed is None else seed + r),
                                    reasoning_effort=spec.reasoning_effort)
                tasks.append((spec, p, r, cid, sampling))

    # Shuffle so models/providers interleave instead of running block-by-block — spreads
    # provider load and gives early cross-model coverage. Seeded for reproducibility.
    random.Random(seed or 0).shuffle(tasks)

    path, write, close, in_memory = _open_sink(out, resume)
    collected = [] if in_memory else None
    ok = failed = 0
    lock = threading.Lock()

    def work(task):
        spec, p, r, cid, sampling = task
        provider = providers[spec.label]
        sem = sems.get(spec.label)
        rec = Record(custom_id=cid, run_id=run_id, provider=spec.provider, model=spec.model,
                     prompt_id=p.id, prompt=p.text, system=system, sampling=sampling,
                     repeat=r, prompt_meta=p.meta, model_meta=spec.meta)
        t0 = time.monotonic()
        try:
            messages = []
            if system:
                messages.append({"role": "system", "content": system})
            messages.append({"role": "user", "content": p.text})
            if sem:
                sem.acquire()
            try:
                text, meta = provider.chat(messages, sampling)
            finally:
                if sem:
                    sem.release()
            meta = meta or {}
            rec.output = text
            rec.finish_reason = meta.get("finish_reason")
            rec.model_returned = meta.get("model_returned")
            rec.served_by = meta.get("served_by")
            rec.usage = normalize_usage(spec.provider, meta.get("usage"))
            rec.cost_usd = estimate_cost(spec.model, rec.usage, prices)
            for k in ("empty_reason", "response_id", "reasoning_effort"):
                if k in meta and meta[k] is not None:
                    rec.raw[k] = meta[k]
            success = True
        except Exception as exc:
            rec.error = {"type": _err_type(exc), "message": str(exc)[:600],
                         "attempts": getattr(exc, "attempts", None)}
            success = False
        rec.latency_ms = int((time.monotonic() - t0) * 1000)
        return rec, success

    with ThreadPoolExecutor(max_workers=concurrency) as pool:
        futures = [pool.submit(work, t) for t in tasks]
        for fut in as_completed(futures):
            rec, success = fut.result()
            line = rec.to_json()
            with lock:
                if write:
                    write(line)
                if collected is not None:
                    collected.append(json.loads(line))
                if success:
                    ok += 1
                else:
                    failed += 1
            if on_record:
                try:
                    on_record(rec)
                except Exception:
                    pass

    if close:
        close()
    return RunResult(path=path, ok=ok, failed=failed, run_id=run_id, _records=collected)

# ===== cli.py =====
def _add_run(sub):
    p = sub.add_parser("run", help="fan prompts across a roster of models (live calls)")
    p.add_argument("prompts", nargs="?", help="prompts file, or '-' for stdin")
    p.add_argument("-p", "--prompt", action="append", metavar="TEXT",
                   help="an inline prompt (repeatable)")
    p.add_argument("-m", "--model", action="append", metavar="PROVIDER:ID",
                   help="a model selector like openai:gpt-4o-mini (repeatable)")
    p.add_argument("--roster", metavar="FILE", help="a roster JSON file of models")
    p.add_argument("-o", "--out", default="-", metavar="FILE",
                   help="output JSONL path, or '-' for stdout (default)")
    p.add_argument("--system", metavar="TEXT", help="system prompt applied to every call")
    p.add_argument("--repeats", type=int, default=1)
    p.add_argument("--temperature", type=float, default=1.0)
    p.add_argument("--top-p", type=float, default=1.0, dest="top_p")
    p.add_argument("--max-tokens", type=int, default=512, dest="max_tokens")
    p.add_argument("--seed", type=int, default=0)
    p.add_argument("--concurrency", type=int, default=16, help="total in-flight calls")
    p.add_argument("--per-model", type=int, default=None, dest="per_model",
                   help="max simultaneous calls to any one model (the 429 guard)")
    p.add_argument("--resume", action="store_true",
                   help="skip cells already complete in --out; fill only the gaps")
    p.add_argument("--retry-errors", action="store_true", dest="retry_errors",
                   help="on resume, also retry cells that previously errored")
    p.add_argument("-q", "--quiet", action="store_true", help="don't print the summary")
    p.set_defaults(func=_cmd_run)


def _cmd_run(args) -> int:
    # prompts: inline -p wins, else positional path/stdin
    if args.prompt:
        prompts = list(args.prompt)
    elif args.prompts:
        prompts = args.prompts
    else:
        print("error: provide prompts (a file, '-', or one or more -p)", file=sys.stderr)
        return 2

    # models: combine -m selectors and a --roster file
    models = list(args.model or [])
    if args.roster:
        models += load_roster(args.roster)
    if not models:
        print("error: provide at least one -m provider:model or a --roster file", file=sys.stderr)
        return 2

    if args.resume and args.out in ("-", ""):
        print("error: --resume needs a file --out (not stdout)", file=sys.stderr)
        return 2

    result = run(
        prompts, models, out=args.out,
        repeats=args.repeats, temperature=args.temperature, top_p=args.top_p,
        max_tokens=args.max_tokens, seed=args.seed,
        concurrency=args.concurrency, per_model_concurrency=args.per_model,
        resume=args.resume, retry_errors=args.retry_errors, system=args.system,
    )
    if not args.quiet:
        where = result.path or "stdout"
        print(f"wrote {result.ok + result.failed} records "
              f"({result.ok} ok, {result.failed} failed) to {where}", file=sys.stderr)
    return 0


def build_parser() -> argparse.ArgumentParser:
    ap = argparse.ArgumentParser(
        prog="aieasybatch",
        description="Brain-dead-simple batch prompting: prompts × a roster of models "
                    "-> one JSONL with every answer. Zero dependencies.",
    )
    ap.add_argument("--version", action="version", version=f"aieasybatch {__version__}")
    sub = ap.add_subparsers(dest="cmd")
    _add_run(sub)
    _maybe_add_optional(sub)
    return ap


def _maybe_add_optional(sub):
    """Register the view/batch verbs if their modules are present (added in later phases)."""
    try:
        add_view(sub)
    except Exception:
        pass
    try:
        add_batch(sub)
    except Exception:
        pass


def main(argv=None) -> int:
    ap = build_parser()
    args = ap.parse_args(argv)
    if not getattr(args, "func", None):
        ap.print_help(sys.stderr)
        return 1
    return args.func(args)

if __name__ == "__main__":
    import sys as _sys
    _sys.exit(main())
